#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

// Read input
const inputPath = process.argv[2];
const outputPath = process.argv[3];

if (!inputPath || !outputPath) {
  console.error('Usage: node ua-arch-analyze.js <input.json> <output.json>');
  process.exit(1);
}

try {
  const rawData = JSON.parse(fs.readFileSync(inputPath, 'utf8'));

  // Convert file paths to node structure
  const files = rawData.files || [];
  const importMap = rawData.importMap || {};

  // Create file nodes with IDs
  const fileNodes = files.map(f => ({
    id: `file:${f.path}`,
    type: classifyNodeType(f.path, f.language),
    name: path.basename(f.path),
    filePath: f.path,
    language: f.language,
    category: f.fileCategory
  }));

  // Create import edges from importMap
  const importEdges = [];
  for (const [sourcePath, targets] of Object.entries(importMap)) {
    if (Array.isArray(targets)) {
      for (const targetPath of targets) {
        importEdges.push({
          source: `file:${sourcePath}`,
          target: `file:${targetPath}`,
          type: 'imports'
        });
      }
    }
  }

  // A. Directory Grouping
  const directoryGroups = groupByDirectory(fileNodes);

  // B. Node Type Grouping
  const nodeTypeGroups = groupByNodeType(fileNodes);

  // C. Import Adjacency Analysis
  const { fileFanIn, fileFanOut } = computeFanInOut(importEdges);

  // D. Cross-Category Dependency (for non-code files, we infer relationships)
  const crossCategoryEdges = inferCrossCategoryEdges(fileNodes);

  // E. Inter-Group Import Frequency
  const interGroupImports = computeInterGroupImports(importEdges, directoryGroups);

  // F. Intra-Group Import Density
  const intraGroupDensity = computeIntraGroupDensity(importEdges, directoryGroups);

  // G. Directory Pattern Matching
  const patternMatches = matchDirectoryPatterns(directoryGroups);

  // H. Deployment Topology Detection
  const deploymentTopology = detectDeploymentTopology(fileNodes);

  // I. Data Pipeline Detection
  const dataPipeline = detectDataPipeline(fileNodes);

  // J. Documentation Coverage
  const docCoverage = computeDocCoverage(fileNodes, directoryGroups);

  // K. Dependency Direction
  const dependencyDirection = computeDependencyDirection(interGroupImports);

  // File statistics
  const fileStats = {
    totalFileNodes: fileNodes.length,
    filesPerGroup: Object.fromEntries(
      Object.entries(directoryGroups).map(([k, v]) => [k, v.length])
    ),
    nodeTypeCounts: Object.fromEntries(
      Object.entries(nodeTypeGroups).map(([k, v]) => [k, v.length])
    )
  };

  // Write output
  const output = {
    scriptCompleted: true,
    directoryGroups,
    nodeTypeGroups,
    crossCategoryEdges,
    interGroupImports,
    intraGroupDensity,
    patternMatches,
    deploymentTopology,
    dataPipeline,
    docCoverage,
    dependencyDirection,
    fileStats,
    fileFanIn,
    fileFanOut
  };

  fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));
  console.log('Analysis complete:', fileStats.totalFileNodes, 'files analyzed');
  process.exit(0);

} catch (error) {
  console.error('Error:', error.message);
  console.error(error.stack);
  process.exit(1);
}

// Helper functions

function classifyNodeType(filePath, language) {
  const basename = path.basename(filePath).toLowerCase();

  // CI/CD pipelines
  if (filePath.match(/\.(github|gitlab|circleci)\//)) return 'pipeline';
  if (basename.match(/^(jenkinsfile|\.gitlab-ci\.yml)$/i)) return 'pipeline';

  // Infrastructure
  if (basename.match(/^dockerfile/i)) return 'service';
  if (basename.match(/docker-compose/)) return 'service';
  if (filePath.endsWith('.tf') || filePath.endsWith('.tfvars')) return 'resource';

  // Config files
  if (basename.match(/^(package\.json|tsconfig\.json|.*\.toml|.*config\.(js|json|yml|yaml))$/)) return 'config';
  if (basename.match(/^(makefile|cmakelist.*\.txt)$/i)) return 'config';

  // Documentation
  if (language === 'markdown' || basename.match(/\.(md|rst)$/)) return 'document';
  if (basename.match(/^(readme|license|notice|changelog|contributing).*$/i)) return 'document';

  // Schema/Data
  if (basename.endsWith('.sql')) return 'schema';
  if (basename.match(/\.(graphql|gql|proto|prisma)$/)) return 'schema';

  // Default to file
  return 'file';
}

function groupByDirectory(fileNodes) {
  const groups = {};

  // Find common prefix
  const paths = fileNodes.map(n => n.filePath);
  const commonPrefix = findCommonPrefix(paths);

  for (const node of fileNodes) {
    let relativePath = node.filePath;
    if (commonPrefix && node.filePath.startsWith(commonPrefix)) {
      relativePath = node.filePath.substring(commonPrefix.length);
    }

    const parts = relativePath.split('/').filter(p => p);
    const topDir = parts[0] || '__root__';

    if (!groups[topDir]) groups[topDir] = [];
    groups[topDir].push(node.id);
  }

  return groups;
}

function findCommonPrefix(paths) {
  if (paths.length === 0) return '';

  const sorted = paths.slice().sort();
  const first = sorted[0];
  const last = sorted[sorted.length - 1];

  let i = 0;
  while (i < first.length && first[i] === last[i]) {
    i++;
  }

  let prefix = first.substring(0, i);
  const lastSlash = prefix.lastIndexOf('/');
  if (lastSlash > 0) {
    prefix = prefix.substring(0, lastSlash + 1);
  } else {
    prefix = '';
  }

  return prefix;
}

function groupByNodeType(fileNodes) {
  const groups = {};
  for (const node of fileNodes) {
    if (!groups[node.type]) groups[node.type] = [];
    groups[node.type].push(node.id);
  }
  return groups;
}

function computeFanInOut(edges) {
  const fanIn = {};
  const fanOut = {};

  for (const edge of edges) {
    fanOut[edge.source] = (fanOut[edge.source] || 0) + 1;
    fanIn[edge.target] = (fanIn[edge.target] || 0) + 1;
  }

  // Sort and return top entries
  const sortedFanIn = Object.entries(fanIn).sort((a, b) => b[1] - a[1]).slice(0, 20);
  const sortedFanOut = Object.entries(fanOut).sort((a, b) => b[1] - a[1]).slice(0, 20);

  return {
    fileFanIn: Object.fromEntries(sortedFanIn),
    fileFanOut: Object.fromEntries(sortedFanOut)
  };
}

function inferCrossCategoryEdges(fileNodes) {
  const edges = [];
  const typeMap = {};

  fileNodes.forEach(n => {
    typeMap[n.id] = n.type;
  });

  // Infer relationships based on conventions
  const configNodes = fileNodes.filter(n => n.type === 'config');
  const docNodes = fileNodes.filter(n => n.type === 'document');
  const serviceNodes = fileNodes.filter(n => n.type === 'service');

  if (configNodes.length > 0) {
    edges.push({ fromType: 'config', toType: 'file', edgeType: 'configures', count: configNodes.length });
  }
  if (docNodes.length > 0) {
    edges.push({ fromType: 'document', toType: 'file', edgeType: 'documents', count: docNodes.length });
  }
  if (serviceNodes.length > 0) {
    edges.push({ fromType: 'service', toType: 'file', edgeType: 'deploys', count: serviceNodes.length });
  }

  return edges;
}

function computeInterGroupImports(edges, directoryGroups) {
  const interGroup = {};

  // Build reverse mapping: nodeId -> group
  const nodeToGroup = {};
  for (const [group, nodes] of Object.entries(directoryGroups)) {
    for (const node of nodes) {
      nodeToGroup[node] = group;
    }
  }

  for (const edge of edges) {
    const sourceGroup = nodeToGroup[edge.source];
    const targetGroup = nodeToGroup[edge.target];

    if (sourceGroup && targetGroup && sourceGroup !== targetGroup) {
      const key = `${sourceGroup} -> ${targetGroup}`;
      interGroup[key] = (interGroup[key] || 0) + 1;
    }
  }

  return Object.entries(interGroup)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([pair, count]) => {
      const [from, to] = pair.split(' -> ');
      return { from, to, count };
    });
}

function computeIntraGroupDensity(edges, directoryGroups) {
  const density = {};

  // Build reverse mapping
  const nodeToGroup = {};
  for (const [group, nodes] of Object.entries(directoryGroups)) {
    for (const node of nodes) {
      nodeToGroup[node] = group;
    }
  }

  const internalEdges = {};
  const totalEdges = {};

  for (const edge of edges) {
    const sourceGroup = nodeToGroup[edge.source];
    const targetGroup = nodeToGroup[edge.target];

    if (sourceGroup) {
      totalEdges[sourceGroup] = (totalEdges[sourceGroup] || 0) + 1;

      if (sourceGroup === targetGroup) {
        internalEdges[sourceGroup] = (internalEdges[sourceGroup] || 0) + 1;
      }
    }
  }

  for (const group of Object.keys(directoryGroups)) {
    const internal = internalEdges[group] || 0;
    const total = totalEdges[group] || 0;
    density[group] = {
      internalEdges: internal,
      totalEdges: total,
      density: total > 0 ? (internal / total) : 0
    };
  }

  return density;
}

function matchDirectoryPatterns(directoryGroups) {
  const patterns = {
    routes: 'api', api: 'api', controllers: 'api', endpoints: 'api', handlers: 'api', serializers: 'api', routers: 'api', blueprints: 'api',
    services: 'service', core: 'service', lib: 'service', domain: 'service', logic: 'service', internal: 'service', composables: 'service', signals: 'service', mailers: 'service', jobs: 'service', channels: 'service',
    models: 'data', db: 'data', data: 'data', persistence: 'data', repository: 'data', entities: 'data', migrations: 'data', entity: 'data', sql: 'data', database: 'data', schema: 'data',
    components: 'ui', views: 'ui', pages: 'ui', ui: 'ui', layouts: 'ui', screens: 'ui',
    middleware: 'middleware', plugins: 'middleware', interceptors: 'middleware', guards: 'middleware',
    utils: 'utility', helpers: 'utility', common: 'utility', shared: 'utility', tools: 'utility', pkg: 'utility', templatetags: 'utility',
    config: 'config', constants: 'config', env: 'config', settings: 'config', management: 'config', commands: 'config',
    test: 'test', tests: 'test', __tests__: 'test', spec: 'test', specs: 'test',
    types: 'types', interfaces: 'types', schemas: 'types', contracts: 'types', dtos: 'types', dto: 'types', request: 'types', response: 'types',
    hooks: 'hooks',
    store: 'state', state: 'state', reducers: 'state', actions: 'state', slices: 'state',
    assets: 'assets', static: 'assets', public: 'assets',
    cmd: 'entry', bin: 'entry',
    docs: 'documentation', documentation: 'documentation', wiki: 'documentation',
    deploy: 'infrastructure', deployment: 'infrastructure', infra: 'infrastructure', infrastructure: 'infrastructure', k8s: 'infrastructure', kubernetes: 'infrastructure', helm: 'infrastructure', charts: 'infrastructure', terraform: 'infrastructure', tf: 'infrastructure', docker: 'infrastructure',
    '.github': 'ci-cd', '.gitlab': 'ci-cd', '.circleci': 'ci-cd'
  };

  const matches = {};
  for (const dir of Object.keys(directoryGroups)) {
    const lowerDir = dir.toLowerCase();
    if (patterns[lowerDir]) {
      matches[dir] = patterns[lowerDir];
    }
  }

  return matches;
}

function detectDeploymentTopology(fileNodes) {
  const infraFiles = fileNodes
    .filter(n => ['service', 'resource', 'pipeline'].includes(n.type))
    .map(n => n.filePath);

  return {
    hasDockerfile: infraFiles.some(f => f.toLowerCase().includes('dockerfile')),
    hasCompose: infraFiles.some(f => f.includes('docker-compose')),
    hasK8s: infraFiles.some(f => f.includes('k8s') || f.includes('kubernetes')),
    hasTerraform: infraFiles.some(f => f.endsWith('.tf')),
    hasCI: infraFiles.some(f => f.includes('.github/workflows') || f.includes('.gitlab-ci')),
    infraFiles: infraFiles.slice(0, 10)
  };
}

function detectDataPipeline(fileNodes) {
  return {
    schemaFiles: fileNodes.filter(n => n.type === 'schema').map(n => n.filePath).slice(0, 10),
    migrationFiles: fileNodes.filter(n => n.filePath.includes('migration')).map(n => n.filePath).slice(0, 10),
    dataModelFiles: fileNodes.filter(n => n.filePath.includes('model')).map(n => n.filePath).slice(0, 10),
    apiHandlerFiles: fileNodes.filter(n => n.filePath.match(/route|handler|controller|api/)).map(n => n.filePath).slice(0, 10)
  };
}

function computeDocCoverage(fileNodes, directoryGroups) {
  const docNodes = fileNodes.filter(n => n.type === 'document');
  const docPaths = new Set(docNodes.map(n => path.dirname(n.filePath)));

  const groupsWithDocs = Object.keys(directoryGroups).filter(group => {
    return docNodes.some(n => n.filePath.startsWith(group + '/') || n.filePath === group);
  });

  const totalGroups = Object.keys(directoryGroups).length;
  const undocumentedGroups = Object.keys(directoryGroups).filter(g => !groupsWithDocs.includes(g));

  return {
    groupsWithDocs: groupsWithDocs.length,
    totalGroups,
    coverageRatio: totalGroups > 0 ? groupsWithDocs.length / totalGroups : 0,
    undocumentedGroups: undocumentedGroups.slice(0, 10)
  };
}

function computeDependencyDirection(interGroupImports) {
  const direction = [];
  const pairs = {};

  for (const { from, to, count } of interGroupImports) {
    const key = [from, to].sort().join('<->');
    if (!pairs[key]) {
      pairs[key] = { from, to, fromToCount: 0, toFromCount: 0 };
    }

    if (pairs[key].from === from) {
      pairs[key].fromToCount = count;
    } else {
      pairs[key].toFromCount = count;
    }
  }

  for (const pair of Object.values(pairs)) {
    if (pair.fromToCount > pair.toFromCount) {
      direction.push({ dependent: pair.from, dependsOn: pair.to });
    } else if (pair.toFromCount > pair.fromToCount) {
      direction.push({ dependent: pair.to, dependsOn: pair.from });
    }
  }

  return direction;
}

