const fs = require('fs');
const results = JSON.parse(fs.readFileSync('.understand-anything/tmp/ua-arch-results.json', 'utf8'));

// Define architecture layers based on analysis
const layers = [
  {
    id: 'layer:android-runtime-mirror',
    name: 'Android ART 运行时镜像层',
    description: '镜像 AOSP ART 运行时的对象模型、DEX 文件格式、GC 堆空间、JNI 接口和线程管理等核心结构',
    nodeIds: results.directoryGroups['android']
  },
  {
    id: 'layer:core-analysis-engine',
    name: '核心分析引擎层',
    description: 'ELF coredump 解析、DWARF 调试信息、多架构栈回溯、内存引用和符号解析的底层实现',
    nodeIds: results.directoryGroups['core']
  },
  {
    id: 'layer:command-system',
    name: '命令系统层',
    description: 'REPL 命令实现，包括 Android 专用命令（class、space、hprof）、核心分析命令（backtrace、thread、mmap）和远程调试支持',
    nodeIds: results.directoryGroups['parser']
  },
  {
    id: 'layer:llvm-support',
    name: 'LLVM C++ 标准库支持层',
    description: '解析和检查 LLVM libc++ 标准库容器（vector、map、string 等）和 scudo 内存分配器的内部状态',
    nodeIds: results.directoryGroups['llvm']
  },
  {
    id: 'layer:utilities',
    name: '工具库层',
    description: '跨平台工具函数、日志系统、内存映射抽象、ZIP 文件处理和调用栈格式化工具',
    nodeIds: results.directoryGroups['utils']
  },
  {
    id: 'layer:configuration',
    name: '配置层',
    description: '构建配置（CMake）、SDK 配置文件（INI）、平台兼容性头文件和嵌入式资源',
    nodeIds: [
      ...results.directoryGroups['CMakeLists.txt'],
      ...results.directoryGroups['ini'],
